function About() {
  return (
    <section className="about-section" id="about">
      <h2>Our Story</h2>
      <p>
        Meow Café started as a two-table corner shop with one very opinionated
        cat. Today it's a full house — good coffee, quiet mornings, and a
        handful of regulars who happen to have paws. Stop by, order a latte,
        and let one of them decide if you're worth sitting next to.
      </p>
    </section>
  );
}

export default About;
